insert into wac_drama_script values (112085, 112, 3, '106431', 'wac_215_idle_normal2_joy', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112086, 112, 3, '118511', 'wac_215_karin_talk_wish', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112087, 112, 21, 'vo_wac_220215', 'vo_wac_220215_015', '0', '0', '', '', '', '');
insert into wac_drama_script values (112088, 112, 11, '118511', '好的，\\n我来准备给各公会的委托函吧。\\n公会召唤！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112089, 112, 91, '112088', '', '', '', '', '', '', '');
insert into wac_drama_script values (112090, 112, 3, '118511', 'wac_215_karin_idle_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112091, 112, 3, '118511', 'wac_215_karin_talk_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112092, 112, 21, 'vo_wac_220215', 'vo_wac_220215_016', '0', '0', '', '', '', '');
insert into wac_drama_script values (112093, 112, 11, '118511', '那么，在各位画画的时候，\\n我就去跟其他公会打招呼吧。\\n用美丽的画作覆盖墙面，\\n一起创造兰德索尔的象征吧！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112094, 112, 91, '112093', '', '', '', '', '', '', '');
insert into wac_drama_script values (112095, 112, 3, '118511', 'wac_215_karin_idle_normal', '1', '', '', '0.2', '', '');
