insert into wac_drama_script values (112097, 112, 21, 'vo_wac_220215', 'vo_wac_220215_017', '0', '0', '', '', '', '');
insert into wac_drama_script values (112098, 112, 11, '105811', '好！\\n那我就画魔物料理——\\nそれじゃあわたしは、魔物料理の絵を――', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112099, 112, 91, '112098', '', '', '', '', '', '', '');
insert into wac_drama_script values (112100, 112, 3, '105811', 'wac_215_peko_idle_wish', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112101, 112, 3, '106011', 'wac_215_kyaru_talk_anger', '0', 'wac_215_talk_arm_crossed_loop', '1', '0.2', '0.2', '');
insert into wac_drama_script values (112102, 112, 21, 'vo_wac_220215', 'vo_wac_220215_018', '0', '0', '', '', '', '');
insert into wac_drama_script values (112103, 112, 11, '106011', '别画那种诡异的东西！\\n不过，计划本身还不坏吧？\\n感觉很有趣……\\n那我们就努力一把吧！', '10', '1', '1', '0', '0', '0.5');
