insert into wac_drama_script values (1012009, 1012, 11, '100711', '布丁，这里也是布丁，\\n那边还有那边也是布丁……\\n我骗你的啦。\\n我会好好按别人教我的画的。', '10', '1', '1', '0', '0', '0.5');
