insert into wac_drama_script values (1012012, 1012, 11, '100711', '唔……但是一想到布丁，\\n我肚子就饿了。\\n所以我就画了布丁，然后把墙吃下去。\\n一点都不好吃！', '10', '1', '1', '0', '0', '0.5');
