insert into wac_drama_script values (1112009, 1112, 11, '105311', '好，成品质量还不错！\\n画画也挺有意思的嘛！\\n虽然有时会被以为是小孩子的恶作剧，\\n还蛮伤人的……', '10', '1', '1', '0', '0', '0.5');
