insert into wac_drama_script values (2112012, 2112, 11, '100511', '重要的是一气呵成，\\n在笔里寄托自己的正义之心。\\n希望城里的坏人\\n能以此为契机觉醒自己的正义之心！', '10', '1', '1', '0', '0', '0.5');
