insert into wac_drama_script values (2612009, 2612, 11, '104011', '嘿嘿，我按要求画好了哦。\\n我不讨厌默默推进工作。\\n但是……我这种人画的画\\n真的能让人满意吗？', '10', '1', '1', '0', '0', '0.5');
