insert into wac_drama_script values (4012009, 4012, 11, '106611', '可、可恶！\\n这里就这样处理，完成！\\n呼。这幅充满了我对老大的愤怒……\\n不对，充满了我对城镇的爱的杰作，完成了。', '10', '1', '1', '0', '0', '0.5');
