insert into wac_drama_script values (4212012, 4212, 11, '105211', '我画了一幅超～可爱的画哦♪\\n看到城墙上有这样的画，\\n大家一定能感受到\\n兰德索尔是个好地方♪', '10', '1', '1', '0', '0', '0.5');
