insert into wac_drama_script values (4212015, 4212, 11, '105211', '我所重视的人们就住在这个城市，\\n能帮这个城市变得更有活力，我非常幸福。\\n希望大家也能\\n在心中感受到这份温暖。', '10', '1', '1', '0', '0', '0.5');
