insert into wac_drama_script values (5212031, 5212, 11, '103011', '不是的！步美的艺术，\\n相当有水平是～也！\\n有侘寂之美♪', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (5212032, 5212, 91, '0', '', '', '', '', '', '', '');
