insert into wac_drama_script values (5212036, 5212, 11, '100811', '谦和的步美小姐\\n用了画来表现自己内在的可爱……\\n我就不会有这种想法♪\\n虽然我还是第一名。', '10', '1', '1', '0', '0', '0.5');
