insert into wac_drama_script values (5212041, 5212, 11, '104511', '大家都画得很好～\\n但是要注意，\\n不要表扬空花哦？空花还是被骂的时候\\n更能拿出干劲！', '10', '1', '1', '0', '0', '0.5');
