insert into wac_drama_script values (6212023, 6212, 11, '106611', '老、老大居然会这么普通地夸人，\\n反而有点吓人了！\\n我是不是应该趁早消灭她，\\n以免之后被她抓住把柄？', '10', '1', '1', '0', '0', '0.5');
