insert into wac_drama_script values (6212028, 6212, 11, '106511', '你就乖乖接受夸奖吧，祈梨。\\n我可是相当\\n喜欢这幅画哦？\\n嘿嘿，下次也要保持这个势头继续画哟！', '10', '1', '1', '0', '0', '0.5');
