insert into wac_drama_script values (8612022, 8612, 11, '105911', '呵呵，像这样\\n和大家一起画画\\n也是一种乐趣呢。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (8612023, 8612, 91, '0', '', '', '', '', '', '', '');
