insert into wac_drama_script values (8612027, 8612, 11, '106411', '是啊。可能因为不习惯，\\n我有点紧张，\\n但和可可萝小姐还有大家在一起，\\n感觉就能安下心来快乐画画呢。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (8612028, 8612, 91, '0', '', '', '', '', '', '', '');
