insert into wac_drama_script values (8612032, 8612, 11, '106011', '比起一个人，还是和大家在一起\\n更安心、更快乐吗……\\n是不是和我们\\n一起吃饭的时候一样呢。', '10', '1', '1', '0', '0', '0.5');
