insert into wac_drama_script values (11512022, 11512, 11, '102111', '画好了！\\n嘿嘿，感觉是我目前为止\\n画得最好的一幅♪\\n说是自信之作，会不会有点夸张呢？', '10', '1', '1', '0', '0', '0.5');
