insert into wac_drama_script values (11512027, 11512, 11, '102311', '好厉害～好厉害！\\n胡桃画得真好！\\n噗吉也在说“好厉害啊！”，\\n是在夸你呢！', '10', '1', '1', '0', '0', '0.5');
