insert into wac_drama_script values (11512037, 11512, 11, '102811', '是靠练演技的时候\\n培养的专注力吧。\\n胡桃是那种只要拿出自信，\\n就能不断进步的类型呢。', '10', '1', '1', '0', '0', '0.5');
